import json
import os

def scan_folder(folder_path):
    """
    Scan a folder of JSON files and report invalid rows with line numbers.

    Args:
    folder_path (str): Path to the folder containing JSON files.
    """
    invalid_rows = []
    for filename in os.listdir(folder_path):
        if filename.endswith(".json"):
            with open(os.path.join(folder_path, filename), "r") as file:
                try:
                    data = json.load(file)
                    for i, row in enumerate(data):
                        if not is_valid_row(row):
                            invalid_rows.append((filename, i + 1, row))
                except json.JSONDecodeError:
                    print(f"Invalid JSON file: {filename}")
    return invalid_rows

def is_valid_row(row):
    """
    Check if a row is valid.

    Args:
    row (dict): JSON row to check.
    """
    # Check if the row is empty
    if not row:
        return False

    # Check if the row has the correct keys
    keys = set(row.keys())
    if not keys:
        return False

    # Check if the values are of the correct type
    for key, value in row.items():
        if not isinstance(value, (int, float, str, bool)):
            return False

    return True

# Example usage
folder_path = "/path/to/folder"
invalid_rows = scan_folder(folder_path)
if invalid_rows:
    print("Invalid rows:")
    for filename, line_number, row in invalid_rows:
        print(f"{filename}: {line_number}: {row}")
else:
    print("No invalid rows found.")
